import{_ as a,o as i,c as t,ag as n}from"./chunks/framework.Culc7SYV.js";const h=JSON.parse('{"title":"AI Usage Policy","description":"","frontmatter":{},"headers":[],"relativePath":"AI-Usage-Policy.md","filePath":"AI-Usage-Policy.md","lastUpdated":1773806339000}'),o={name:"AI-Usage-Policy.md"};function r(s,e,l,d,c,u){return i(),t("div",null,[...e[0]||(e[0]=[n('<h1 id="ai-usage-policy" tabindex="-1">AI Usage Policy <a class="header-anchor" href="#ai-usage-policy" aria-label="Permalink to &quot;AI Usage Policy&quot;">​</a></h1><p>Last modified: 07/03/2026</p><h2 id="purpose" tabindex="-1">Purpose <a class="header-anchor" href="#purpose" aria-label="Permalink to &quot;Purpose&quot;">​</a></h2><p>This policy explains how LearnKit&#39;s AI features should be used and what users can expect when generating study content.</p><h2 id="scope" tabindex="-1">Scope <a class="header-anchor" href="#scope" aria-label="Permalink to &quot;Scope&quot;">​</a></h2><p>This policy applies to AI-assisted features in LearnKit, including:</p><ul><li>Card suggestion and generation from note content.</li><li>AI chat assistance for study and review workflows.</li></ul><h2 id="what-ai-features-do" tabindex="-1">What AI Features Do <a class="header-anchor" href="#what-ai-features-do" aria-label="Permalink to &quot;What AI Features Do&quot;">​</a></h2><p>LearnKit AI features are designed to suggest draft study content, not final truth.</p><p>Depending on your settings and prompt, AI output may include:</p><ul><li>Basic, cloze, and other card suggestions.</li><li>Question and answer drafts.</li><li>Difficulty estimates and rationale text.</li><li>Explanations for note content in a study context.</li></ul><h2 id="human-review-is-required" tabindex="-1">Human Review Is Required <a class="header-anchor" href="#human-review-is-required" aria-label="Permalink to &quot;Human Review Is Required&quot;">​</a></h2><p>AI output can be wrong, incomplete, biased, or outdated.</p><p>Before saving or studying AI-generated cards, users should:</p><ul><li>Verify factual accuracy.</li><li>Correct unclear wording.</li><li>Remove unsafe or irrelevant suggestions.</li><li>Ensure card difficulty and scope are appropriate.</li></ul><p>LearnKit treats AI output as a draft for user review.</p><h2 id="data-handling-and-privacy" tabindex="-1">Data Handling and Privacy <a class="header-anchor" href="#data-handling-and-privacy" aria-label="Permalink to &quot;Data Handling and Privacy&quot;">​</a></h2><p>When AI features are used, LearnKit may send selected content to the configured AI provider in order to generate a response.</p><p>Depending on user settings, this can include:</p><ul><li>Note content.</li><li>Note path or contextual metadata.</li><li>Referenced image information when image support is enabled.</li><li>User prompts and custom instructions.</li></ul><p>Users are responsible for reviewing provider terms and privacy policies before enabling AI features.</p><p>API keys configured for AI providers are stored locally in the plugin folder at <code>.obsidian/plugins/sprout/configuration/api-keys.json</code>.</p><p>The folder name remains <code>sprout</code> for compatibility, even though the plugin name is LearnKit.</p><p>If you track <code>.obsidian</code> plugin files in Git, add only this file to <code>.gitignore</code> to avoid accidentally sharing credentials while letting other LearnKit configuration files sync across devices.</p><h2 id="sensitive-and-confidential-data" tabindex="-1">Sensitive and Confidential Data <a class="header-anchor" href="#sensitive-and-confidential-data" aria-label="Permalink to &quot;Sensitive and Confidential Data&quot;">​</a></h2><p>Do not submit content that is highly sensitive, regulated, or confidential unless you fully understand and accept the data handling implications.</p><p>Examples include:</p><ul><li>Personal health information.</li><li>Financial account details.</li><li>Passwords, API keys, or private credentials.</li><li>Private client, workplace, or exam-restricted material.</li></ul><h2 id="copyright-and-content-rights" tabindex="-1">Copyright and Content Rights <a class="header-anchor" href="#copyright-and-content-rights" aria-label="Permalink to &quot;Copyright and Content Rights&quot;">​</a></h2><p>Users must only submit content they have the right to use.</p><p>Users are responsible for ensuring AI-generated cards do not infringe copyright, violate licensing terms, or misuse protected materials.</p><h2 id="safety-and-educational-use" tabindex="-1">Safety and Educational Use <a class="header-anchor" href="#safety-and-educational-use" aria-label="Permalink to &quot;Safety and Educational Use&quot;">​</a></h2><p>LearnKit AI features are intended for learning support only.</p><p>They are not a substitute for professional advice in medical, legal, financial, or safety-critical domains.</p><h2 id="availability-and-limits" tabindex="-1">Availability and Limits <a class="header-anchor" href="#availability-and-limits" aria-label="Permalink to &quot;Availability and Limits&quot;">​</a></h2><p>AI features may change over time and can be affected by:</p><ul><li>Provider uptime and model changes.</li><li>Rate limits or token limits.</li><li>Cost controls set by the user or provider.</li></ul><p>LearnKit does not guarantee uninterrupted AI availability or output quality.</p><h2 id="policy-updates" tabindex="-1">Policy Updates <a class="header-anchor" href="#policy-updates" aria-label="Permalink to &quot;Policy Updates&quot;">​</a></h2><p>This policy may be updated as AI features evolve.</p><p>Material updates will be reflected by changing the Last modified date on this page.</p>',41)])])}const f=a(o,[["render",r]]);export{h as __pageData,f as default};
